import { each } from '../../../../utils/zcutils';
import { getAxisObject } from '../../../../axis/axisutils';

export function UpdateViewportArea_C(behaviourEventInstance, selectionManager, transform) {
    let eventManager = this,
        zoomInstance = behaviourEventInstance.instance,
        plotBrush = eventManager.behaviours.PLOT_BRUSH,
        chart = eventManager.chart,
        domainInfo = selectionManager.point,
        behaviours = eventManager.behaviours;

    chart.disableAnimation = false;

    // if (domainInfo.x && domainInfo.x[0].domain) {
    //     chart.viewPortExtent = domainInfo.x[0].domain;
    // }

    each(domainInfo, (axis, type) => {
        each(axis, (info, index) => {
            let axisInfo = getAxisObject(chart, type, index);
            if (axisInfo.scale.ordinalRange) {
                axisInfo.scale.ordinalRange = null;
            }
        });
    });

    let extent = [[0, 0], [chart.plotarea.width, chart.plotarea.height]];
    if (plotBrush) {
        plotBrush.instance.updateExtent(extent);
    }
    // #ZC2123
    chart.positionEventTrackerElement();

    zoomInstance.updateExtent(extent);
    chart.zooming = false;
    chart.brushing = false;
    if(chart.scroll){
        if(chart.scroll.scrollDomain){
            chart.scroll.visiblePointCount = chart.scroll.scrollDomain.length;
        }
    }
    // if (!behaviours.PLOT_ZOOM) {
        this.chart.eventHandler.oldBrushComponent = "";
        this.chart.eventHandler.activeBrushComponent = "";
        this.chart.eventHandler.selectionDomain = {};
    // }
}
